    "original_url" varchar(1024),
    "file_url" varchar(1024),
    "source_provider" varchar(128),
    "evidence_text" clob,
    "target_type" varchar(32),
    "target_id" bigint,
    "review_status" varchar(32) NOT NULL,
    "status" varchar(32) NOT NULL,
    "creator" varchar(64) DEFAULT '',
    "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) DEFAULT '',
    "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT '0',
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "xunjing_ai_eval_set" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "project_id" bigint NOT NULL,
    "name" varchar(128) NOT NULL,
    "scene_code" varchar(64) NOT NULL,
    "status" varchar(32) NOT NULL,
    "creator" varchar(64) DEFAULT '',
    "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) DEFAULT '',
    "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT '0',
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "xunjing_ai_eval_case" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "eval_set_id" bigint NOT NULL,
    "question" varchar(512) NOT NULL,
    "expected_policy" clob NOT NULL,
    "risk_tags" varchar(512),
    "source_required" bit NOT NULL DEFAULT TRUE,
    "status" varchar(32) NOT NULL,
    "creator" varchar(64) DEFAULT '',
    "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) DEFAULT '',
    "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT '0',
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "xunjing_ai_quota_rule" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "project_id" bigint NOT NULL,
    "scope_type" varchar(32) NOT NULL,
    "scope_id" bigint,
    "scene_code" varchar(64) NOT NULL,
    "daily_limit" int NOT NULL,
    "monthly_budget" decimal(18, 6),
    "cache_enabled" bit NOT NULL DEFAULT TRUE,
    "fallback_model_code" varchar(64),
    "status" varchar(32) NOT NULL,
    "creator" varchar(64) DEFAULT '',
    "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) DEFAULT '',
    "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT '0',
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "xunjing_ai_generation_log" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "project_id" bigint NOT NULL,
    "school_id" bigint,
    "package_id" bigint NOT NULL,
    "qr_code_id" bigint,
    "scene_code" varchar(64) NOT NULL,
    "user_trace_id" varchar(128),
    "model_code" varchar(64) NOT NULL,
    "prompt_version" varchar(64),
    "input_summary" clob,
    "output_summary" clob,
    "source_json" clob,
    "token_count" bigint NOT NULL DEFAULT 0,
    "cost_amount" decimal(18, 6) NOT NULL DEFAULT 0,
    "safety_status" varchar(32) NOT NULL,
    "cache_hit" bit NOT NULL DEFAULT FALSE,
    "creator" varchar(64) DEFAULT '',
    "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) DEFAULT '',
    "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT '0',
    PRIMARY KEY ("id")
);
